arguments.command:
cat > /tmp/test_stackalloc.cs << 'EOF'
using System;

class Program
{
    static void Main()
    {
        Span<nint> a = stackalloc nint[4];
        a[0] = 42;
        a[1] = nint.MaxValue;
        Console.WriteLine($"nint span: [{a[0]}, {a[1]}, {a[2]}, {a[3]}]");
        Console.WriteLine($"nint size: {sizeof(nint)} bytes");

        Span<nuint> b = stackalloc nuint[3];
        b[0] = 99;
        b[1] = nuint.MaxValue;
        Console.WriteLine($"nuint span: [{b[0]}, {b[1]}, {b[2]}]");
        Console.WriteLine($"nuint size: {sizeof(nuint)} bytes");

        Console.WriteLine("Success!");
    }
}
EOF
cd /tmp && dotnet run --project . 2>/dev/null || dotnet-script test_stackalloc.cs 2>/dev/null || (dotnet new console -o stackalloc_test --force -n StackAllocTest && cp test_stackalloc.cs stackalloc_test/Program.cs && cd stackalloc_test && dotnet run)

